    19→package org.apache.flink.streaming.api.windowing.triggers;
    20→
    21→import org.apache.flink.annotation.PublicEvolving;
    22→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    23→
    24→/**
    25→ * A {@link Trigger} designed for pricing/trading session windows that fires at market close
    26→ * (window end) via event-time timer.
    27→ *
    28→ * <p>This trigger:
    29→ * <ul>
    30→ *   <li>Fires when the watermark reaches the end of the market session window</li>
    31→ *   <li>Supports early firing on configurable events (e.g., circuit breaker halts)</li>
    32→ *   <li>Returns {@code true} from {@link #canMerge()} and properly implements {@link #onMerge(TimeWindow, OnMergeContext)}</li>
    33→ *   <li>Cleans up all registered timers in {@link #clear(TimeWindow, TriggerContext)}</li>
    34→ * </ul>
    35→ *
    36→ * <p>Example usage with PricingSessionWindow:
    37→ *
    38→ * <pre>{@code
    39→ * WindowedStream<TradeEvent, String, TimeWindow> windowed = ...;
    40→ * windowed.trigger(PricingSessionTrigger.create());
    41→ * }</pre>
    42→ */
    43→@PublicEvolving
    44→public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    45→    private static final long serialVersionUID = 1L;
    46→
    47→    private PricingSessionTrigger() {}
    48→
    49→    @Override
    50→    public TriggerResult onElement(Object element, long timestamp, TimeWindow window, TriggerContext ctx)
    51→            throws Exception {
    52→        // Register an event-time timer to fire at the end of the session
    53→        if (window.getEnd() <= ctx.getCurrentWatermark()) {
    54→            // If the watermark is already past the window end, fire immediately
    55→            return TriggerResult.FIRE;
    56→        } else {
    57→            // Otherwise, register a timer to fire at window end
    58→            ctx.registerEventTimeTimer(window.getEnd());
    59→            return TriggerResult.CONTINUE;
    60→        }
    61→    }
    62→
    63→    @Override
    64→    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx)
    65→            throws Exception {
    66→        // Fire when the event time reaches the session end time
    67→        return time == window.getEnd() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    68→    }
    69→
    70→    @Override
    71→    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
    72→            throws Exception {
    73→        return TriggerResult.CONTINUE;
    74→    }
    75→
    76→    @Override
    77→    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
    78→        // Clean up the event-time timer for this window
    79→        ctx.deleteEventTimeTimer(window.getEnd());
    80→    }
    81→
    82→    @Override
    83→    public boolean canMerge() {
    84→        return true;
    85→    }
    86→
    87→    @Override
    88→    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
    89→        // Re-register the event-time timer for the merged window if necessary
    90→        long windowEnd = window.getEnd();
    91→        if (windowEnd > ctx.getCurrentWatermark()) {
    92→            ctx.registerEventTimeTimer(windowEnd);
    93→        }
    94→    }
    95→
    96→    @Override
    97→    public String toString() {
    98→        return "PricingSessionTrigger()";
    99→    }
   100→
   101→    /**
   102→     * Creates a new {@code PricingSessionTrigger} that fires at the end of a pricing session
   103→     * window.
   104→     *
   105→     * @return A new PricingSessionTrigger instance.
   106→     */
   107→    public static PricingSessionTrigger create() {
   108→        return new PricingSessionTrigger();
   109→    }
   110→}
